#include <stdio.h>
#include <string.h>
#include <math.h>
#include <stdlib.h>
#include <cuda_runtime.h>
#include <cuda.h>

//Structure to hold a node information
struct Node
{
	int starting;
	int no_of_edges;
};

// Kernel function to perform BFS
__global__ void bfs_kernel(int* h_graph_edges, bool* h_graph_mask, Node* h_graph_nodes, bool* h_graph_visited, int* h_cost, bool* stop, int no_of_nodes) {
	int tid = blockIdx.x * blockDim.x + threadIdx.x;
	if (tid < no_of_nodes) {
		if (h_graph_mask[tid] == true) {
			h_graph_mask[tid] = false;
			for (int i = h_graph_nodes[tid].starting; i < (h_graph_nodes[tid].no_of_edges + h_graph_nodes[tid].starting); i++) {
				int id = h_graph_edges[i];
				if (!h_graph_visited[id]) {
					h_cost[id] = h_cost[tid] + 1;
					*(stop) = true;
				}
			}
		}
	}
}

// Kernel function to update the graph mask
__global__ void update_kernel(bool* h_updating_graph_mask, bool* h_graph_mask, bool* h_graph_visited, int* h_cost, bool* stop, int no_of_nodes) {
	int tid = blockIdx.x * blockDim.x + threadIdx.x;
	if (tid < no_of_nodes) {
		if (h_updating_graph_mask[tid] == true) {
			h_graph_mask[tid] = true;
			h_graph_visited[tid] = true;
			*(stop) = true;
			h_updating_graph_mask[tid] = false;
		}
	}
}

void BFSGraph(int argc, char** argv);

void Usage(int argc, char** argv) {
	fprintf(stderr, "Usage: %s <input_file>\n", argv[0]);
}

int main(int argc, char** argv) {
	BFSGraph(argc, argv);
	return 0;
}

void BFSGraph(int argc, char** argv) {
	int no_of_nodes = 0;
	int edge_list_size = 0;
	char* input_f;
	input_f = argv[1];

	printf("Reading File\n");
	//Read in Graph from a file
	FILE* fp = fopen(input_f, "r");
	if (!fp) {
		printf("Error Reading graph file\n");
		return;
	}

	int source = 0;

	fscanf(fp, "%d", &no_of_nodes);

	// allocate host memory
	Node* h_graph_nodes = (Node*)malloc(sizeof(Node) * no_of_nodes);
	bool* h_graph_mask = (bool*)malloc(sizeof(bool) * no_of_nodes);
	bool* h_updating_graph_mask = (bool*)malloc(sizeof(bool) * no_of_nodes);
	bool* h_graph_visited = (bool*)malloc(sizeof(bool) * no_of_nodes);

	int start, edgeno;
	// initalize the memory
	for (unsigned int i = 0; i < no_of_nodes; i++) {
		fscanf(fp, "%d %d", &start, &edgeno);
		h_graph_nodes[i].starting = start;
		h_graph_nodes[i].no_of_edges = edgeno;
		h_graph_mask[i] = false;
		h_updating_graph_mask[i] = false;
		h_graph_visited[i] = false;
	}

	//read the source node from the file
	fscanf(fp, "%d", &source);

	// source=0; //tesing code line

	//set the source node as true in the mask
	h_graph_mask[source] = true;
	h_graph_visited[source] = true;

	fscanf(fp, "%d", &edge_list_size);

	int id, cost;
	int* h_graph_edges = (int*)malloc(sizeof(int) * edge_list_size);
	for (int i = 0; i < edge_list_size; i++) {
		fscanf(fp, "%d", &id);
		fscanf(fp, "%d", &cost);
		h_graph_edges[i] = id;
	}

	if (fp)
		fclose(fp);

	// allocate mem for the result on host side
	int* h_cost = (int*)malloc(sizeof(int) * no_of_nodes);
	for (int i = 0; i < no_of_nodes; i++)
		h_cost[i] = -1;
	h_cost[source] = 0;

	// allocate device memory
	Node* d_graph_nodes;
	bool* d_graph_mask;
	bool* d_updating_graph_mask;
	bool* d_graph_visited;
	int* d_graph_edges;
	int* d_cost;
	bool* d_stop;

	cudaMalloc((void**)&d_graph_nodes, sizeof(Node) * no_of_nodes);
	cudaMalloc((void**)&d_graph_mask, sizeof(bool) * no_of_nodes);
	cudaMalloc((void**)&d_updating_graph_mask, sizeof(bool) * no_of_nodes);
	cudaMalloc((void**)&d_graph_visited, sizeof(bool) * no_of_nodes);
	cudaMalloc((void**)&d_graph_edges, sizeof(int) * edge_list_size);
	cudaMalloc((void**)&d_cost, sizeof(int) * no_of_nodes);
	cudaMalloc((void**)&d_stop, sizeof(bool));

	// copy data from host to device
	cudaMemcpy(d_graph_nodes, h_graph_nodes, sizeof(Node) * no_of_nodes, cudaMemcpyHostToDevice);
	cudaMemcpy(d_graph_mask, h_graph_mask, sizeof(bool) * no_of_nodes, cudaMemcpyHostToDevice);
	cudaMemcpy(d_updating_graph_mask, h_updating_graph_mask, sizeof(bool) * no_of_nodes, cudaMemcpyHostToDevice);
	cudaMemcpy(d_graph_visited, h_graph_visited, sizeof(bool) * no_of_nodes, cudaMemcpyHostToDevice);
	cudaMemcpy(d_graph_edges, h_graph_edges, sizeof(int) * edge_list_size, cudaMemcpyHostToDevice);
	cudaMemcpy(d_cost, h_cost, sizeof(int) * no_of_nodes, cudaMemcpyHostToDevice);

	int k = 0;
	bool stop = false;
	cudaMemcpy(d_stop, &stop, sizeof(bool), cudaMemcpyHostToDevice);

	printf("Start traversing the tree\n");

	do {
		stop = false;
		cudaMemcpy(d_stop, &stop, sizeof(bool), cudaMemcpyHostToDevice);

		bfs_kernel << <(no_of_nodes + 255) / 256, 256 >> > (d_graph_edges, d_graph_mask, d_graph_nodes, d_graph_visited, d_cost, d_stop, no_of_nodes);
		cudaDeviceSynchronize();

		update_kernel << <(no_of_nodes + 255) / 256, 256 >> > (d_updating_graph_mask, d_graph_mask, d_graph_visited, d_cost, d_stop, no_of_nodes);
		cudaDeviceSynchronize();

		cudaMemcpy(&stop, d_stop, sizeof(bool), cudaMemcpyDeviceToHost);
		k++;
	} while (stop);

	// copy result from device to host
	cudaMemcpy(h_cost, d_cost, sizeof(int) * no_of_nodes, cudaMemcpyDeviceToHost);

	//Store the result into a file
	FILE* fpo = fopen("result.txt", "w");
	for (int i = 0; i < no_of_nodes; i++)
		fprintf(fpo, "%d) cost:%d\n", i, h_cost[i]);
	fclose(fpo);
	printf("Result stored in result.txt\n");

	// cleanup memory
	free(h_graph_nodes);
	free(h_graph_edges);
	free(h_graph_mask);
	free(h_updating_graph_mask);
	free(h_graph_visited);
	free(h_cost);

	cudaFree(d_graph_nodes);
	cudaFree(d_graph_mask);
	cudaFree(d_updating_graph_mask);
	cudaFree(d_graph_visited);
	cudaFree(d_graph_edges);
	cudaFree(d_cost);
	cudaFree(d_stop);
}

