#include <stdio.h>
#include <stdlib.h>
#include <cuda_runtime.h>
#include <sys/time.h>

// Returns the current system time in microseconds 
long long get_time()
{
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000) + tv.tv_usec;

}

#define BLOCK_SIZE 16
#define BLOCK_SIZE_C BLOCK_SIZE
#define BLOCK_SIZE_R BLOCK_SIZE

#define STR_SIZE	256

/* maximum power density possible (say 300W for a 10mm x 10mm chip)	*/
#define MAX_PD	(3.0e6)
/* required precision in degrees	*/
#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
/* capacitance fitting factor	*/
#define FACTOR_CHIP	0.5

typedef float FLOAT;

/* chip parameters	*/
const FLOAT t_chip = 0.0005;
const FLOAT chip_height = 0.016;
const FLOAT chip_width = 0.016;

/* ambient temperature, assuming no package at all	*/
const FLOAT amb_temp = 80.0;

/* Single iteration of the transient solver in the grid model.
 * advances the solution of the discretized difference equations 
 * by one time step
 */
__global__ void single_iteration(FLOAT *result, FLOAT *temp, FLOAT *power, int row, int col,
					  FLOAT Cap_1, FLOAT Rx_1, FLOAT Ry_1, FLOAT Rz_1, 
					  FLOAT step)
{
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int idy = blockIdx.y * blockDim.y + threadIdx.y;
    int index = idy * col + idx;

    if (idx >= col || idy >= row) return;

    FLOAT delta;
    int r = idy;
    int c = idx;

    /* Corner 1 */
    if ( (r == 0) && (c == 0) ) {
        delta = (Cap_1) * (power[0] +
            (temp[1] - temp[0]) * Rx_1 +
            (temp[col] - temp[0]) * Ry_1 +
            (amb_temp - temp[0]) * Rz_1);
    }	/* Corner 2 */
    else if ((r == 0) && (c == col-1)) {
        delta = (Cap_1) * (power[c] +
            (temp[c-1] - temp[c]) * Rx_1 +
            (temp[c+col] - temp[c]) * Ry_1 +
        (   amb_temp - temp[c]) * Rz_1);
    }	/* Corner 3 */
    else if ((r == row-1) && (c == col-1)) {
        delta = (Cap_1) * (power[r*col+c] + 
            (temp[r*col+c-1] - temp[r*col+c]) * Rx_1 + 
            (temp[(r-1)*col+c] - temp[r*col+c]) * Ry_1 + 
        (   amb_temp - temp[r*col+c]) * Rz_1);					
    }	/* Corner 4	*/
    else if ((r == row-1) && (c == 0)) {
        delta = (Cap_1) * (power[r*col] + 
            (temp[r*col+1] - temp[r*col]) * Rx_1 + 
            (temp[(r-1)*col] - temp[r*col]) * Ry_1 + 
            (amb_temp - temp[r*col]) * Rz_1);
    }	/* Edge 1 */
    else if (r == 0) {
        delta = (Cap_1) * (power[c] + 
            (temp[c+1] + temp[c-1] - 2.0*temp[c]) * Rx_1 + 
            (temp[col+c] - temp[c]) * Ry_1 + 
            (amb_temp - temp[c]) * Rz_1);
    }	/* Edge 2 */
    else if (c == col-1) {
        delta = (Cap_1) * (power[r*col+c] + 
            (temp[(r+1)*col+c] + temp[(r-1)*col+c] - 2.0*temp[r*col+c]) * Ry_1 + 
            (temp[r*col+c-1] - temp[r*col+c]) * Rx_1 + 
            (amb_temp - temp[r*col+c]) * Rz_1);
    }	/* Edge 3 */
    else if (r == row-1) {
        delta = (Cap_1) * (power[r*col+c] + 
            (temp[r*col+c+1] + temp[r*col+c-1] - 2.0*temp[r*col+c]) * Rx_1 + 
            (temp[(r-1)*col+c] - temp[r*col+c]) * Ry_1 + 
            (amb_temp - temp[r*col+c]) * Rz_1);
    }	/* Edge 4 */
    else if (c == 0) {
        delta = (Cap_1) * (power[r*col] + 
            (temp[(r+1)*col] + temp[(r-1)*col] - 2.0*temp[r*col]) * Ry_1 + 
            (temp[r*col+1] - temp[r*col]) * Rx_1 + 
            (amb_temp - temp[r*col]) * Rz_1);
    } else {
        delta = (Cap_1) * (power[r*col+c] + 
            (temp[(r+1)*col+c] + temp[(r-1)*col+c] - 2.f*temp[r*col+c]) * Ry_1 + 
            (temp[r*col+c+1] + temp[r*col+c-1] - 2.f*temp[r*col+c]) * Rx_1 + 
            (amb_temp - temp[r*col+c]) * Rz_1);
    }

    result[index] = temp[index] + delta;
}

void compute_tran_temp(FLOAT *result, int num_iterations, FLOAT *temp, FLOAT *power, int row, int col, FLOAT *d_result, FLOAT *d_temp, FLOAT *d_power) 
{
    FLOAT grid_height = chip_height / row;
    FLOAT grid_width = chip_width / col;

    FLOAT Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
    FLOAT Rx = grid_width / (2.0 * K_SI * t_chip * grid_height);
    FLOAT Ry = grid_height / (2.0 * K_SI * t_chip * grid_width);
    FLOAT Rz = t_chip / (K_SI * grid_height * grid_width);

    FLOAT max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    FLOAT step = PRECISION / max_slope / 1000.0;

    FLOAT Rx_1=1.f/Rx;
    FLOAT Ry_1=1.f/Ry;
    FLOAT Rz_1=1.f/Rz;
    FLOAT Cap_1 = step/Cap;

    dim3 block(BLOCK_SIZE, BLOCK_SIZE);
    dim3 grid((col + block.x - 1) / block.x, (row + block.y - 1) / block.y);

    FLOAT* r = d_result;
    FLOAT* t = d_temp;

    for (int i = 0; i < num_iterations ; i++)
    {
        single_iteration<<<grid, block>>>(r, t, d_power, row, col, Cap_1, Rx_1, Ry_1, Rz_1, step);
        FLOAT* tmp = t;
        t = r;
        r = tmp;
        cudaDeviceSynchronize();
    }	
}

void fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);
	exit(1);
}

void writeoutput(FLOAT *vect, int grid_rows, int grid_cols, char *file) {

    int i,j, index=0;
    FILE *fp;
    char str[STR_SIZE];

    if( (fp = fopen(file, "w" )) == 0 )
        printf( "The file was not opened\n" );


    for (i=0; i < grid_rows; i++) 
        for (j=0; j < grid_cols; j++)
        {

            sprintf(str, "%d\t%g\n", index, vect[i*grid_cols+j]);
            fputs(str,fp);
            index++;
        }

    fclose(fp);	
}

void read_input(FLOAT *vect, int grid_rows, int grid_cols, char *file)
{
  	int i, index;
	FILE *fp;
	char str[STR_SIZE];
