}

int main(int argc, char **argv)
{
	int grid_rows, grid_cols, sim_time, i;
	FLOAT *temp, *power, *result, *d_temp, *d_power, *d_result;
	char *tfile, *pfile, *ofile;

	/* check validity of inputs	*/
	if (argc != 7)
		usage(argc, argv);
	if ((grid_rows = atoi(argv[1])) <= 0 ||
		(grid_cols = atoi(argv[2])) <= 0 ||
		(sim_time = atoi(argv[3])) <= 0 
		)
		usage(argc, argv);

	/* allocate memory for the temperature and power arrays	*/
	temp = (FLOAT *) calloc (grid_rows * grid_cols, sizeof(FLOAT));
	power = (FLOAT *) calloc (grid_rows * grid_cols, sizeof(FLOAT));
	result = (FLOAT *) calloc (grid_rows * grid_cols, sizeof(FLOAT));
	if(!temp || !power)
		fatal("unable to allocate memory");

	/* read initial temperatures and input power	*/
	tfile = argv[4];
	pfile = argv[5];
    ofile = argv[6];

	read_input(temp, grid_rows, grid_cols, tfile);
	read_input(power, grid_rows, grid_cols, pfile);

    cudaMalloc((void**)&d_temp, grid_rows * grid_cols * sizeof(FLOAT));
    cudaMalloc((void**)&d_power, grid_rows * grid_cols * sizeof(FLOAT));
    cudaMalloc((void**)&d_result, grid_rows * grid_cols * sizeof(FLOAT));

    cudaMemcpy(d_temp, temp, grid_rows * grid_cols * sizeof(FLOAT), cudaMemcpyHostToDevice);
    cudaMemcpy(d_power, power, grid_rows * grid_cols * sizeof(FLOAT), cudaMemcpyHostToDevice);

	printf("Start computing the transient temperature\n");

