__global__ void nw_optimized_kernel(int *input_itemsets, int *referrence, int max_rows, int max_cols, int penalty) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int idy = blockIdx.y * blockDim.y + threadIdx.y;

    if (idx < max_cols && idy < max_rows) {
        int b_index_x = idx / BLOCK_SIZE;
        int b_index_y = idy / BLOCK_SIZE;

        __shared__ int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
        __shared__ int reference_l[BLOCK_SIZE * BLOCK_SIZE];

        if (threadIdx.x < BLOCK_SIZE && threadIdx.y < BLOCK_SIZE) {
            reference_l[threadIdx.y * BLOCK_SIZE + threadIdx.x] = referrence[max_cols * (b_index_y * BLOCK_SIZE + threadIdx.y + 1) + b_index_x * BLOCK_SIZE + threadIdx.x + 1];
        }

        if (threadIdx.x < BLOCK_SIZE + 1 && threadIdx.y < BLOCK_SIZE + 1) {
            input_itemsets_l[threadIdx.y * (BLOCK_SIZE + 1) + threadIdx.x] = input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + threadIdx.y) + b_index_x * BLOCK_SIZE + threadIdx.x];
        }

        __syncthreads();

        if (threadIdx.x > 0 && threadIdx.x < BLOCK_SIZE + 1 && threadIdx.y > 0 && threadIdx.y < BLOCK_SIZE + 1) {
            input_itemsets_l[threadIdx.y * (BLOCK_SIZE + 1) + threadIdx.x] = maximum(input_itemsets_l[(threadIdx.y - 1) * (BLOCK_SIZE + 1) + threadIdx.x - 1] + reference_l[(threadIdx.y - 1) * BLOCK_SIZE + threadIdx.x - 1],
                    input_itemsets_l[threadIdx.y * (BLOCK_SIZE + 1) + threadIdx.x - 1] - penalty,
                    input_itemsets_l[(threadIdx.y - 1) * (BLOCK_SIZE + 1) + threadIdx.x] - penalty);
        }

        __syncthreads();

        if (threadIdx.x < BLOCK_SIZE && threadIdx.y < BLOCK_SIZE) {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + threadIdx.y + 1) + b_index_x * BLOCK_SIZE + threadIdx.x + 1] = input_itemsets_l[(threadIdx.y + 1) * (BLOCK_SIZE + 1) + threadIdx.x + 1];
        }
    }
}

void nw_optimized(int *input_itemsets, int *output_itemsets, int *referrence, int max_rows, int max_cols, int penalty) {
    int *d_input_itemsets, *d_referrence;
    cudaMalloc((void **)&d_input_itemsets, max_rows * max_cols * sizeof(int));
