#include <stdio.h>
#include <math.h>
#include <sys/time.h>
#include <limits.h>

#define PI 3.1415926535897932

// Define constants
__constant__ long M = INT_MAX;
__constant__ int A = 1103515245;
__constant__ int C = 12345;

// Function to get time
__host__ long long get_time() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000) + tv.tv_usec;
}

// Function to calculate elapsed time
__host__ float elapsed_time(long long start_time, long long end_time) {
    return (float) (end_time - start_time) / (1000 * 1000);
}

// Function to round a double to an integer
__device__ double roundDouble(double value) {
    int newValue = (int)(value);
    if (value - newValue < 0.5)
        return newValue;
    else
        return newValue + 1;
}

// Kernel to set values in a 3D array
__global__ void setIfKernel(int testValue, int newValue, int* array3D, int dimX, int dimY, int dimZ) {
    int x = blockIdx.x * blockDim.x + threadIdx.x;
    int y = blockIdx.y * blockDim.y + threadIdx.y;
    int z = blockIdx.z * blockDim.z + threadIdx.z;

    if (x < dimX && y < dimY && z < dimZ) {
        if (array3D[x * dimY * dimZ + y * dimZ + z] == testValue)
            array3D[x * dimY * dimZ + y * dimZ + z] = newValue;
    }
}

// Kernel to generate a uniformly distributed random number
__device__ double randu(int* seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((double) M));
}

// Kernel to generate a normally distributed random number
__device__ double randn(int* seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2 * PI * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

// Kernel to add noise to a 3D array
__global__ void addNoiseKernel(int* array3D, int dimX, int dimY, int dimZ, int* seed) {
    int x = blockIdx.x * blockDim.x + threadIdx.x;
    int y = blockIdx.y * blockDim.y + threadIdx.y;
    int z = blockIdx.z * blockDim.z + threadIdx.z;

    if (x < dimX && y < dimY && z < dimZ) {
        array3D[x * dimY * dimZ + y * dimZ + z] = array3D[x * dimY * dimZ + y * dimZ + z] + (int)(5 * randn(seed, 0));
