// Kernel to calculate the particle filter
__global__ void particleFilterKernel(int* I, int IszX, int IszY, int Nfr, int* seed, int Nparticles) {
    int x = blockIdx.x * blockDim.x + threadIdx.x;

    if (x < Nparticles) {
        // Apply motion model
        double arrayX = roundDouble(IszY / 2.0);
        double arrayY = roundDouble(IszX / 2.0);
        arrayX += 1 + 5 * randn(seed, x);
        arrayY += -2 + 2 * randn(seed, x);

        // Calculate likelihood
        int indX, indY;
        double likelihood = 0;
        for (int y = 0; y < 25; y++) {
            indX = roundDouble(arrayX) + y % 5 - 2;
            indY = roundDouble(arrayY) + y / 5 - 2;
            int ind = indX * IszY * Nfr + indY * Nfr + 1;
            if (ind >= IszX * IszY * Nfr)
                ind = 0;
            likelihood += (pow((I[ind] - 100), 2) - pow((I[ind] - 228), 2)) / 50.0;
        }
        likelihood /= 25;

        // Update and normalize weights
        double weights = likelihood;
        weights = weights * exp(likelihood);
    }
